public class SubstringCounter {

   public static void main(String[] args) {
       Scanner input = new Scanner(System.in); //create scanner object

       String mainString; //declaration of main string
       String subString; //declaration of substring
       int count; //declaration of count variable
       String repeat = "Y"; //setting repeat variable to 'Y' by default

       while (repeat.equalsIgnoreCase("Y")) { //while the user wants to repeat
           System.out.print("Enter the main string: ");
           mainString = input.nextLine(); //read the main string
           System.out.print("Enter the substring: ");
           subString = input.nextLine(); //read the substring

           count = 0; //initialize count variable
           for (int I = 0; I <= mainString.length() - subString.length(); i++) { //loop through the main string
               if (mainString.substring(i, I + subString.length()).equals(subString)) { //check if the substring occurs in the main string
                   count++; //increment count
               }
           }

           System.out.println("The string \"" + subString + "\" occurs " + count + " time(s) in the main string \"" + mainString + "\".");

           System.out.print("Do you want to repeat? (Y/N): ");
           repeat = input.nextLine(); //ask the user if they want to repeat
       }

       System.out.println("Goodbye!"); //when the user is done repeating
   }

} 

