struct Node<T> {
    data: T,
    next: Option<Box<Node<T>>>,
}

impl<T> Node<T> {
    fn new(data: T) -> Node<T> {
        Node { data: data, next: None }
    }
}

pub struct LinkedList<T> {
    head: Option<Box<Node<T>>>,
}

impl<T> LinkedList<T> {
    pub fn new() -> LinkedList<T> {
        LinkedList { head: None }
    }

    pub fn add_node(&mut self, data: T) {
        let new_node = Box::new(Node::new(data));
        match self.head.take() {
            None => self.head = Some(new_node),
            Some(old_head) => {
                let mut current_node = old_head;
                while let Some(next_node) = current_node.next.as_mut() {
                    current_node = next_node.take();
                }
                current_node.next = Some(new_node);
                self.head = Some(old_head);
            }
        }
    }

    pub fn delete_node(&mut self, data: T) {
        if let Some(old_head) = self.head.take() {
            if old_head.data == data {
                self.head = old_head.next;
            } else {
                let mut current_node = old_head;
                while let Some(ref mut next_node) = current_node.next {
                    if next_node.data == data {
                        current_node.next = next_node.next.take();
                        break;
                    } else {
                        current_node = next_node.as_mut();
                    }
                }
                self.head = Some(old_head);
            }
        }
    }

    pub fn search_node(&self, data: T) -> Option<usize> {
        let mut current_node = self.head.as_ref();
        let mut counter = 0;
        while let Some(node) = current_node {
            if node.data == data {
                return Some(counter);
            } else {
                current_node = node.next.as_ref();
                counter += 1;
            }
        }
        None
    }

    pub fn display_list(&self) {
        let mut current_node = self.head.as_ref();
        while let Some(node) = current_node {
            print!("{} ", node.data);
            current_node = node.next.as_ref();
        }
        println!();
    }

    pub fn update_node(&mut self, old_data: T, new_data: T) {
        let mut current_node = self.head.as_mut();
        while let Some(node) = current_node {
            if node.data == old_data {
                node.data = new_data;
                break;
            } else {
                current_node = node.next.as_mut();
            }
        }
    }

    pub fn reverse_list(&mut self) {
        let mut current_node = self.head.take();
        let mut new_head = None;
        while let Some(mut node) = current_node.take() {
            current_node = node.next.take();
            node.next = new_head.take();
            new_head = Some(node);
        }
        self.head = new_head;
    }
}

fn main() {
    let mut list = LinkedList::new();
    list.add_node(1);
    list.add_node(2);
    list.add_node(3);
    list.add_node(4);
    list.display_list();  // Output: 1 2 3 4
    list.delete_node(3);
    list.display_list();  // Output: 1 2 4
    println!("{:?}", list.search_node(2));  // Output: Some(1)
    list.update_node(2, 5);
    list.display_list();  // Output: 1 5 4
    list.reverse_list();
    list.display_list();  // Output: 4 5 1
}
