pub fn sort_list(&mut self) {
    if let Some(old_head) = self.head.take() {
        // Create a vector to store the values of each node in the list
        let mut node_values = Vec::new();
        let mut current_node = old_head;
        while let Some(next_node) = current_node.next.as_mut() {
            node_values.push(current_node.data);
            current_node = next_node.take();
        }
        node_values.push(current_node.data);

        // Sort the vector and recreate the linked list
        node_values.sort();
        let mut new_head = Box::new(Node::new(node_values[0]));
        let mut current_node = new_head.as_mut();
        for value in &node_values[1..] {
            let new_node = Box::new(Node::new(*value));
            current_node.next = Some(new_node);
            current_node = current_node.next.as_mut().unwrap();
        }
        self.head = Some(new_head);
    }
}
```

This implementation sorts the values of each node in the list by creating a vector and sorting it using Rust's built-in `sort()` method, then recreates the linked list using the sorted values.

